import pytest

def test_non_hr_admin_export_returns_403(
    <employee_token_fixture>,
    <api_client_fixture>
):
    resp = <api_client_fixture>.get(
        "/api/employees/export.csv",
        headers={"Authorization": f"Bearer {<employee_token_fixture>}"}
    )
    assert resp.status_code == 403
    body = resp.json()
    assert "error" in body or "detail" in body

def test_unauthenticated_export_returns_401_or_403(
    <api_client_fixture>
):
    resp = <api_client_fixture>.get("/api/employees/export.csv")
    assert resp.status_code in (401, 403)
